## Step 8: `packages/rest-api-client-generator/src/model-renderer.ts`

This is the core code-generation module. It is a pure function: given a DMMF model plus the full set of enum names, it returns a string of TypeScript source.

### Design decisions addressed here

**whereUnique parameter typing (Q1)**

The `findUnique`, `update`, and `delete` methods each accept a `where` parameter. The strategy is:

1. Look for any field that has `isId: true` — take the first one found.
2. If no `@id` field exists (composite key or no id at all), fall back to all fields with `isUnique: true`.
3. If neither exists, use `Record<string, unknown>` as a last resort.

This is encoded in a helper `buildWhereUniqueType(model)` that returns an inline TypeScript type literal like `{ id: number }` or `{ email: string } | { username: string }`.

**create omission (Q2)**

For the `create` method's data parameter, the following fields are excluded from the interface:
- `kind === 'object'` (relations, already excluded from the model interface)
- `isGenerated === true` (auto-managed DB columns)
- `isId === true && hasDefaultValue === true` (auto-increment / cuid / uuid `@id` fields)

Fields that remain required in create input: any non-relation, non-generated field where `isRequired && !hasDefaultValue`. Fields that are optional in create input: `!isRequired` or `hasDefaultValue` (but not excluded above).

**composite key models (Q3)**

When `model.primaryKey` is non-null (composite `@@id`), there is no single DMMF field with `isId: true`. In this case `buildWhereUniqueType` uses `model.primaryKey.fields` to build a compound where type: `{ field1: T1; field2: T2 }`. This covers the most important case. Composite unique fields (`@@unique`) are handled analogously by falling back to `model.uniqueFields`.

```typescript
import type * as DMMF from '@prisma/dmmf'
import { prismaTypeToTs } from './type-mapper'

// ------------------------------------------------------------------ helpers

function toPlural(name: string): string {
  // Naive English pluralisation: append 's'. A production implementation
  // could use the `pluralize` package already used by client-generator-ts,
  // but we keep this package dependency-free for simplicity.
  return `${name}s`
}

function toRoutePath(name: string): string {
  // e.g. User -> /users, BlogPost -> /blog-posts
  return (
    '/' +
    name
      .replace(/([A-Z])/g, (m, l, i) => (i === 0 ? l.toLowerCase() : `-${l.toLowerCase()}`))
      .toLowerCase() +
    's'
  )
}

/**
 * Returns only the data-bearing scalar + enum fields for a model
 * (skips relation fields with kind === 'object' and kind === 'unsupported').
 */
function dataFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
}

/**
 * Renders a TypeScript field declaration like:
 *   name: string
 *   role?: Role
 *   tags: string[]
 */
function renderFieldDecl(field: DMMF.Field, optional = false): string {
  const tsType = prismaTypeToTs(field.type, field.kind === 'enum')
  const listSuffix = field.isList ? '[]' : ''
  const optMarker = optional || !field.isRequired ? '?' : ''
  return `  ${field.name}${optMarker}: ${tsType}${listSuffix}`
}

// ------------------------------------------------------------------ whereUnique

/**
 * Builds the TypeScript type for the `where` parameter of findUnique/update/delete.
 *
 * Priority:
 *   1. Single @id field
 *   2. Composite @@id (model.primaryKey)
 *   3. @unique fields as a union
 *   4. Composite @@unique (model.uniqueFields)
 *   5. Fallback: Record<string, unknown>
 */
function buildWhereUniqueType(model: DMMF.Model, enumNames: Set<string>): string {
  const fields = model.fields

  // 1. Single @id
  const idField = fields.find((f) => f.isId)
  if (idField) {
    const tsType = prismaTypeToTs(idField.type, enumNames.has(idField.type))
    return `{ ${idField.name}: ${tsType} }`
  }

  // 2. Composite @@id
  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    const parts = model.primaryKey.fields.map((fname) => {
      const f = fields.find((ff) => ff.name === fname)
      if (!f) return `${fname}: unknown`
      return `${fname}: ${prismaTypeToTs(f.type, enumNames.has(f.type))}`
    })
    return `{ ${parts.join('; ')} }`
  }

  // 3. @unique fields
  const uniqueFields = fields.filter((f) => f.isUnique && (f.kind === 'scalar' || f.kind === 'enum'))
  if (uniqueFields.length > 0) {
    return uniqueFields
      .map((f) => `{ ${f.name}: ${prismaTypeToTs(f.type, enumNames.has(f.type))} }`)
      .join(' | ')
  }

  // 4. Composite @@unique
  if (model.uniqueFields.length > 0) {
    const sets = model.uniqueFields.map((fieldNames) => {
      const parts = fieldNames.map((fname) => {
        const f = fields.find((ff) => ff.name === fname)
        if (!f) return `${fname}: unknown`
        return `${fname}: ${prismaTypeToTs(f.type, enumNames.has(f.type))}`
      })
      return `{ ${parts.join('; ')} }`
    })
    return sets.join(' | ')
  }

  return 'Record<string, unknown>'
}

// ------------------------------------------------------------------ create input

/**
 * A field is included in the CreateInput if:
 *   - it is a scalar or enum (not an object relation)
 *   - it is not isGenerated
 *   - it is not (isId && hasDefaultValue)  [e.g., autoincrement / cuid id fields]
 */
function createInputFields(model: DMMF.Model): readonly DMMF.Field[] {
  return dataFields(model).filter((f) => {
    if (f.isGenerated) return false
    if (f.isId && f.hasDefaultValue) return false
    return true
  })
}

// ------------------------------------------------------------------ main renderers

export function renderEnumType(e: DMMF.DatamodelEnum): string {
  const values = e.values.map((v) => `  | '${v.name}'`).join('\n')
  return `export type ${e.name} =\n${values}\n`
}

export function renderModelInterface(model: DMMF.Model, _enumNames: Set<string>): string {
  const fields = dataFields(model)
  const lines = fields.map((f) => renderFieldDecl(f)).join('\n')
  return `export interface ${model.name} {\n${lines}\n}\n`
}

export function renderCrudClass(model: DMMF.Model, enumNames: Set<string>): string {
  const routePath = toRoutePath(model.name)
  const whereUniqueType = buildWhereUniqueType(model, enumNames)

  // Build CreateInput interface inline
  const createFields = createInputFields(model)
  const createLines = createFields
    .map((f) => {
      // Optional if not required or has a default
      const isOptional = !f.isRequired || f.hasDefaultValue
      return renderFieldDecl(f, isOptional)
    })
    .join('\n')
  const createInputType = createLines.length > 0
    ? `{\n${createLines}\n}`
    : 'Record<string, never>'

  // UpdateInput: same as CreateInput but all fields optional
  const updateLines = createFields.map((f) => renderFieldDecl(f, true)).join('\n')
  const updateInputType = updateLines.length > 0
    ? `{\n${updateLines}\n}`
    : 'Record<string, never>'

  return `\
export class ${model.name}Client {
  constructor(private readonly baseUrl: string) {}

  private url(path = ''): string {
    return \`\${this.baseUrl}${routePath}\${path}\`
  }

  async findMany(params?: { where?: Partial<${model.name}>; skip?: number; take?: number }): Promise<${model.name}[]> {
    const query = params ? '?' + new URLSearchParams(Object.entries(params).map(([k, v]) => [k, String(v)])).toString() : ''
    const res = await fetch(this.url() + query)
    if (!res.ok) throw new Error(\`GET ${routePath} failed: \${res.status}\`)
    return res.json() as Promise<${model.name}[]>
  }

  async findUnique(params: { where: ${whereUniqueType} }): Promise<${model.name} | null> {
    const id = Object.values(params.where).join(',')
    const res = await fetch(this.url(\`/\${id}\`))
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`GET ${routePath}/:id failed: \${res.status}\`)
    return res.json() as Promise<${model.name}>
  }

  async create(params: { data: ${createInputType} }): Promise<${model.name}> {
    const res = await fetch(this.url(), {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) throw new Error(\`POST ${routePath} failed: \${res.status}\`)
    return res.json() as Promise<${model.name}>
  }

  async update(params: { where: ${whereUniqueType}; data: ${updateInputType} }): Promise<${model.name}> {
    const id = Object.values(params.where).join(',')
    const res = await fetch(this.url(\`/\${id}\`), {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!res.ok) throw new Error(\`PATCH ${routePath}/:id failed: \${res.status}\`)
    return res.json() as Promise<${model.name}>
  }

  async delete(params: { where: ${whereUniqueType} }): Promise<${model.name}> {
    const id = Object.values(params.where).join(',')
    const res = await fetch(this.url(\`/\${id}\`), { method: 'DELETE' })
    if (!res.ok) throw new Error(\`DELETE ${routePath}/:id failed: \${res.status}\`)
    return res.json() as Promise<${model.name}>
  }
}
`
}
