## Step 9: `packages/rest-api-client-generator/src/generate-client.ts`

This is the orchestration layer. It is responsible for:
1. Accumulating in-memory `Map<filename, string>` of content.
2. Writing files to the output directory using `fs/promises`.

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { renderCrudClass, renderEnumType, renderModelInterface } from './model-renderer'

export interface GenerateRestApiClientOptions {
  outputDir: string
  models: readonly DMMF.Model[]
  enums: readonly DMMF.DatamodelEnum[]
}

/**
 * Builds all file contents in memory as a Map<relativePath, source>.
 * Pure function — no I/O — allows unit testing without the filesystem.
 */
export function buildFileMap(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): Map<string, string> {
  const fileMap = new Map<string, string>()
  const enumNames = new Set(enums.map((e) => e.name))

  // enums.ts — only emitted when there are enums
  if (enums.length > 0) {
    const enumSource = enums.map(renderEnumType).join('\n')
    fileMap.set('enums.ts', enumSource)
  }

  // <Model>.ts — one file per model
  const modelImports: string[] = []
  for (const model of models) {
    const interfaceSource = renderModelInterface(model, enumNames)
    const crudSource = renderCrudClass(model, enumNames)

    // Prepend enum import if any fields reference enums
    const modelUsesEnums =
      enums.length > 0 && model.fields.some((f) => f.kind === 'enum')
    const enumImport = modelUsesEnums ? `import type { ${
      [...new Set(model.fields.filter((f) => f.kind === 'enum').map((f) => f.type))].join(', ')
    } } from './enums'\n\n` : ''

    fileMap.set(`${model.name}.ts`, `${enumImport}${interfaceSource}\n${crudSource}`)
    modelImports.push(model.name)
  }

  // index.ts — barrel + factory
  const importLines = modelImports
    .map((name) => `import { ${name}, ${name}Client } from './${name}'`)
    .join('\n')

  const enumImportLine = enums.length > 0
    ? `export * from './enums'\n`
    : ''

  const modelExportLines = modelImports
    .map((name) => `export type { ${name} } from './${name}'`)
    .join('\n')

  const clientProperties = modelImports
    .map((name) => {
      const prop = name.charAt(0).toLowerCase() + name.slice(1)
      return `  readonly ${prop}: ${name}Client`
    })
    .join('\n')

  const clientAssignments = modelImports
    .map((name) => {
      const prop = name.charAt(0).toLowerCase() + name.slice(1)
      return `    this.${prop} = new ${name}Client(baseUrl)`
    })
    .join('\n')

  const indexSource = `\
// Auto-generated by @prisma/rest-api-client-generator. Do not edit manually.
${importLines}

${enumImportLine}${modelExportLines}

export class RestApiClient {
${clientProperties}

  constructor(baseUrl: string) {
${clientAssignments}
  }
}

export function createRestApiClient(baseUrl: string): RestApiClient {
  return new RestApiClient(baseUrl)
}
`
  fileMap.set('index.ts', indexSource)

  return fileMap
}

/**
 * Writes the generated REST API client files to the output directory.
 */
export async function generateRestApiClient(options: GenerateRestApiClientOptions): Promise<void> {
  const { outputDir, models, enums } = options

  // Clean and recreate the output directory
  await fs.rm(outputDir, { recursive: true, force: true })
  await fs.mkdir(outputDir, { recursive: true })

  const fileMap = buildFileMap(models, enums)

  await Promise.all(
    [...fileMap.entries()].map(([relativePath, content]) =>
      fs.writeFile(path.join(outputDir, relativePath), content, 'utf-8'),
    ),
  )
}
```

The separation between `buildFileMap` (pure) and `generateRestApiClient` (I/O) is the key design choice for testability.

