import type * as DMMF from '@prisma/dmmf'

import { prismaTypeToTs } from './type-mapper'

/**
 * Renders a TypeScript union type alias for a Prisma enum.
 *
 * Example output:
 * ```ts
 * export type Role =
 *   | 'ADMIN'
 *   | 'USER'
 * ```
 */
export function renderEnumType(e: DMMF.DatamodelEnum): string {
  const members = e.values.map((v) => `  | '${v.name}'`).join('\n')
  return `export type ${e.name} =\n${members}\n`
}

/**
 * Renders a TypeScript `interface` for a Prisma model, including only scalar
 * and enum fields (relation fields with `kind === 'object'` are excluded).
 */
export function renderModelInterface(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines: string[] = []
  for (const field of model.fields) {
    if (field.kind === 'object') continue
    const tsType = prismaTypeToTs(field.type, field.kind === 'enum')
    const listSuffix = field.isList ? '[]' : ''
    const optionalMark = field.isRequired ? '' : '?'
    lines.push(`  ${field.name}${optionalMark}: ${tsType}${listSuffix}`)
  }
  return `export interface ${model.name} {\n${lines.join('\n')}\n}\n`
}

/**
 * Builds a TypeScript type expression for a model's unique-identifier
 * (used as the `where` parameter in `findUnique`, `update`, and `delete`).
 *
 * Priority:
 * 1. Single `@id` field
 * 2. Composite `@@id` via `model.primaryKey`
 * 3. Single unique fields as a union
 * 4. Composite `@@unique` groups as a union
 * 5. Fallback: `Record<string, unknown>`
 */
function buildWhereUniqueType(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const idField = model.fields.find((f) => f.isId)
  if (idField) {
    const tsType = prismaTypeToTs(idField.type, idField.kind === 'enum')
    return `{ ${idField.name}: ${tsType} }`
  }

  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    const parts = model.primaryKey.fields.map((name) => {
      const f = model.fields.find((field) => field.name === name)
      const tsType = f ? prismaTypeToTs(f.type, f.kind === 'enum') : 'unknown'
      return `${name}: ${tsType}`
    })
    return `{ ${parts.join('; ')} }`
  }

  const uniqueFields = model.fields.filter((f) => f.isUnique && f.kind !== 'object')
  if (uniqueFields.length > 0) {
    return uniqueFields
      .map((f) => {
        const tsType = prismaTypeToTs(f.type, f.kind === 'enum')
        return `{ ${f.name}: ${tsType} }`
      })
      .join(' | ')
  }

  if (model.uniqueFields.length > 0) {
    return model.uniqueFields
      .map((group) => {
        const parts = group.map((name) => {
          const f = model.fields.find((field) => field.name === name)
          const tsType = f ? prismaTypeToTs(f.type, f.kind === 'enum') : 'unknown'
          return `${name}: ${tsType}`
        })
        return `{ ${parts.join('; ')} }`
      })
      .join(' | ')
  }

  return 'Record<string, unknown>'
}

/**
 * Returns the subset of fields that belong in the `create` data payload:
 * excludes relation fields, DB-generated columns, and auto-id fields.
 */
function createInputFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => {
    if (f.kind === 'object') return false
    if (f.isGenerated) return false
    if (f.isId && f.hasDefaultValue) return false
    return true
  })
}

/**
 * Converts a PascalCase model name to a kebab-case plural URL segment.
 *
 * Examples: `User` → `users`, `BlogPost` → `blog-posts`
 */
function toKebabPlural(name: string): string {
  const kebab = name
    .replace(/([A-Z])/g, (match, letter, offset) => (offset === 0 ? letter : `-${letter}`))
    .toLowerCase()
  return `${kebab}s`
}

/**
 * Renders a `<Model>Client` class with five typed CRUD methods that call a
 * REST API at the provided `baseUrl` using the global `fetch` API.
 */
export function renderCrudClass(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const name = model.name
  const route = `/${toKebabPlural(name)}`
  const whereType = buildWhereUniqueType(model, enumNames)

  const createFields = createInputFields(model)
  const createDataLines = createFields.map((f) => {
    const tsType = prismaTypeToTs(f.type, f.kind === 'enum')
    const listSuffix = f.isList ? '[]' : ''
    const optionalMark = f.isRequired ? '' : '?'
    return `    ${f.name}${optionalMark}: ${tsType}${listSuffix}`
  })
  const createDataType =
    createDataLines.length > 0 ? `{\n${createDataLines.join('\n')}\n  }` : 'Record<string, unknown>'

  const updateDataLines = createFields.map((f) => {
    const tsType = prismaTypeToTs(f.type, f.kind === 'enum')
    const listSuffix = f.isList ? '[]' : ''
    return `    ${f.name}?: ${tsType}${listSuffix}`
  })
  const updateDataType =
    updateDataLines.length > 0 ? `{\n${updateDataLines.join('\n')}\n  }` : 'Record<string, unknown>'

  return `export class ${name}Client {
  readonly #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl.replace(/\\/$/, '')
  }

  async findMany(params?: Record<string, string>): Promise<${name}[]> {
    const query = params ? '?' + new URLSearchParams(params).toString() : ''
    const res = await fetch(\`\${this.#baseUrl}${route}\${query}\`)
    if (!res.ok) throw new Error(\`findMany ${name} failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique({ where }: { where: ${whereType} }): Promise<${name} | null> {
    const id = encodeURIComponent(String(Object.values(where)[0]))
    const res = await fetch(\`\${this.#baseUrl}${route}/\${id}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`findUnique ${name} failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async create({ data }: { data: ${createDataType} }): Promise<${name}> {
    const res = await fetch(\`\${this.#baseUrl}${route}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`create ${name} failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async update({ where, data }: { where: ${whereType}; data: ${updateDataType} }): Promise<${name}> {
    const id = encodeURIComponent(String(Object.values(where)[0]))
    const res = await fetch(\`\${this.#baseUrl}${route}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`update ${name} failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }

  async delete({ where }: { where: ${whereType} }): Promise<${name}> {
    const id = encodeURIComponent(String(Object.values(where)[0]))
    const res = await fetch(\`\${this.#baseUrl}${route}/\${id}\`, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`delete ${name} failed: \${res.status} \${res.statusText}\`)
    return res.json() as Promise<${name}>
  }
}
`
}

