import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { buildFileMap } from './generate-client'
import { renderCrudClass, renderEnumType, renderModelInterface } from './model-renderer'
import { prismaTypeToTs } from './type-mapper'

// ---------------------------------------------------------------------------
// Fixtures
// ---------------------------------------------------------------------------

const roleEnum: DMMF.DatamodelEnum = {
  name: 'Role',
  values: [
    { name: 'ADMIN', dbName: null },
    { name: 'USER', dbName: null },
  ],
}

const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  primaryKey: null,
  uniqueFields: [],
  uniqueIndexes: [],
  fields: [
    {
      kind: 'scalar',
      name: 'id',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: true,
      isReadOnly: false,
      type: 'Int',
      hasDefaultValue: true,
      default: { name: 'autoincrement', args: [] },
    },
    {
      kind: 'scalar',
      name: 'email',
      isRequired: true,
      isList: false,
      isUnique: true,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'scalar',
      name: 'name',
      isRequired: false,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'String',
      hasDefaultValue: false,
    },
    {
      kind: 'enum',
      name: 'role',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'Role',
      hasDefaultValue: true,
      default: 'USER',
    },
    {
      kind: 'object',
      name: 'posts',
      isRequired: false,
      isList: true,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      type: 'Post',
      hasDefaultValue: false,
      relationName: 'PostToUser',
    },
  ],
}

const compositeModel: DMMF.Model = {
  name: 'PostTag',
  dbName: null,
  schema: null,
  primaryKey: { name: null, fields: ['postId', 'tagId'] },
  uniqueFields: [],
  uniqueIndexes: [],
  fields: [
    {
      kind: 'scalar',
      name: 'postId',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: true,
      type: 'Int',
      hasDefaultValue: false,
    },
    {
      kind: 'scalar',
      name: 'tagId',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: true,
      type: 'Int',
      hasDefaultValue: false,
    },
  ],
}

// ---------------------------------------------------------------------------
// prismaTypeToTs
// ---------------------------------------------------------------------------

describe('prismaTypeToTs', () => {
  test('maps all scalar types', () => {
    expect(prismaTypeToTs('String', false)).toBe('string')
    expect(prismaTypeToTs('Boolean', false)).toBe('boolean')
    expect(prismaTypeToTs('Int', false)).toBe('number')
    expect(prismaTypeToTs('Float', false)).toBe('number')
    expect(prismaTypeToTs('Decimal', false)).toBe('number')
    expect(prismaTypeToTs('BigInt', false)).toBe('bigint')
    expect(prismaTypeToTs('DateTime', false)).toBe('Date')
    expect(prismaTypeToTs('Json', false)).toBe('Record<string, unknown>')
    expect(prismaTypeToTs('Bytes', false)).toBe('Uint8Array')
  })

  test('passes enum names through unchanged', () => {
    expect(prismaTypeToTs('Role', true)).toBe('Role')
    expect(prismaTypeToTs('Status', true)).toBe('Status')
  })

  test('returns unknown for unrecognised scalar', () => {
    expect(prismaTypeToTs('Unsupported', false)).toBe('unknown')
  })
})

// ---------------------------------------------------------------------------
// renderEnumType
// ---------------------------------------------------------------------------

describe('renderEnumType', () => {
  test('renders a union type alias', () => {
    expect(renderEnumType(roleEnum)).toMatchInlineSnapshot(`
      "export type Role =
        | 'ADMIN'
        | 'USER'
      "
    `)
  })
})

// ---------------------------------------------------------------------------
// renderModelInterface
// ---------------------------------------------------------------------------

describe('renderModelInterface', () => {
  const enumNames = new Set(['Role'])

  test('includes scalar and enum fields, excludes relations', () => {
    const output = renderModelInterface(userModel, enumNames)
    expect(output).toContain('id: number')
    expect(output).toContain('email: string')
    expect(output).toContain('name?: string')
    expect(output).toContain('role: Role')
    expect(output).not.toContain('posts')
  })

  test('interface shape', () => {
    expect(renderModelInterface(userModel, enumNames)).toMatchInlineSnapshot(`
      "export interface User {
        id: number
        email: string
        name?: string
        role: Role
      }
      "
    `)
  })
})

// ---------------------------------------------------------------------------
// renderCrudClass
// ---------------------------------------------------------------------------

describe('renderCrudClass', () => {
  const enumNames = new Set(['Role'])

  test('uses single @id field for where type', () => {
    const output = renderCrudClass(userModel, enumNames)
    expect(output).toContain('where: { id: number }')
  })

  test('uses composite @@id for where type', () => {
    const output = renderCrudClass(compositeModel, new Set())
    expect(output).toContain('where: { postId: number; tagId: number }')
  })

  test('excludes auto-id from create data', () => {
    const output = renderCrudClass(userModel, enumNames)
    // The id field has isId=true and hasDefaultValue=true so it must be absent from create data
    expect(output).not.toMatch(/data:.*\bid:/)
  })

  test('derives kebab-case plural route from model name', () => {
    const output = renderCrudClass(userModel, enumNames)
    expect(output).toContain('/users')
  })
})

// ---------------------------------------------------------------------------
// buildFileMap
// ---------------------------------------------------------------------------

describe('buildFileMap', () => {
  test('emits enums.ts when enums are present', () => {
    const map = buildFileMap([userModel], [roleEnum])
    expect(map.has('enums.ts')).toBe(true)
    expect(map.get('enums.ts')).toContain("export type Role =")
  })

  test('does not emit enums.ts when there are no enums', () => {
    const map = buildFileMap([compositeModel], [])
    expect(map.has('enums.ts')).toBe(false)
  })

  test('emits a file for each model', () => {
    const map = buildFileMap([userModel, compositeModel], [roleEnum])
    expect(map.has('User.ts')).toBe(true)
    expect(map.has('PostTag.ts')).toBe(true)
  })

  test('model file contains enum import when model uses enums', () => {
    const map = buildFileMap([userModel], [roleEnum])
    expect(map.get('User.ts')).toContain("import type { Role } from './enums'")
  })

  test('model file has no enum import when model uses no enums', () => {
    const map = buildFileMap([compositeModel], [])
    expect(map.get('PostTag.ts')).not.toContain("import type {")
  })

  test('index.ts contains factory function and RestApiClient class', () => {
    const map = buildFileMap([userModel], [roleEnum])
    const index = map.get('index.ts')!
    expect(index).toContain('export function createRestApiClient')
    expect(index).toContain('export class RestApiClient')
    expect(index).toContain('readonly user: UserClient')
  })

  test('index.ts re-exports model types', () => {
    const map = buildFileMap([userModel], [roleEnum])
    const index = map.get('index.ts')!
    expect(index).toContain("export type { User } from './User'")
  })
})

